script.code:
let entry = {{workflowparams:allData}};

if(entry.purchase_order_no_type !== -9999 && (
  !entry.purchase_order_no || entry.purchase_order_no === null || entry.purchase_order_no === ''
)) {
  entry.purchase_order_no = 'draft'
}

return { entry };

return {
  required_fields: JSON.stringify([
  { name: "po_plant", label: "Plant" },
  { name: "purchase_order_no", label: "PO Number" },
  {
    name: "table_po",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    po_plant: {{node:code_draft_check_doc_no.data.entry.po_plant}},
    purchase_order_no: {{node:code_draft_check_doc_no.data.entry.purchase_order_no}},
    table_po: {{node:code_draft_check_doc_no.data.entry.table_po}}
  })
}

let entry = {{workflowparams:allData}};

if (
  entry.purchase_order_no_type !== -9999 &&
  (!entry.purchase_order_no ||
    entry.purchase_order_no === null ||
    entry.purchase_order_no === "" ||
    entry.previous_status == "Draft")
) {
  entry.purchase_order_no = 'issued'
}

return { entry };

return {
  required_fields: JSON.stringify([
  { name: "po_supplier_id", label: "Supplier Name" },
  { name: "po_plant", label: "Plant" },
  { name: "purchase_order_no", label: "PO Number" },
  {
    name: "table_po",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    po_supplier_id: {{node:code_check_doc_no.data.entry.po_supplier_id}},
    po_plant: {{node:code_check_doc_no.data.entry.po_plant}},
    purchase_order_no: {{node:code_check_doc_no.data.entry.purchase_order_no}},
    table_po: {{node:code_check_doc_no.data.entry.table_po}}
  })
}

let table = {{node:code_check_doc_no.data.entry}};

table.table_po = table.table_po.filter(item => (item.item_name || item.item_desc || item.item_id) && item.quantity > 0)

return { table };

const draftGRCount = {{node:search_draft_gr.data.total}};
const draftPICount = {{node:search_draft_pi.data.total}};
let message = [];
let status = 'Passed';

if(draftGRCount > 0) {
  const draftGRNo = {{node:search_draft_gr.data.data.gr_no}};
  message.push(draftGRNo);
}

if(draftPICount > 0) {
  const draftPINo = {{node:search_draft_pi.data.data.purchase_invoice_no}};
  message.push(draftPINo);
}

if(message.length > 0) {
  status = 'Failed'
}

return {
  status: status,
  message: status === 'Passed' ? '' : 'The purchase order has existing GR/PI records in draft status. Proceeding will delete these record: ' + message.join(', ')
}

let updatedLineItem = [];
let entry = {{workflowparams:allData.po_status}} == 'Draft' ? {{node:code_draft_check_doc_no.data.entry}} : {{node:code_filter_lines.data.table}};

for(const [index, poLineItem] of entry.table_po.entries()) {
  const receivedQty = poLineItem.received_qty === null || poLineItem.received_qty === undefined || poLineItem.received_qty === '' ? 0 : parseFloat(poLineItem.received_qty);
  const formattedItem = {
    ...poLineItem,
    quantity: parseFloat(poLineItem.quantity || 0).toFixed(3),
    unit_price: parseFloat(poLineItem.unit_price || 0).toFixed(4),
    gross: parseFloat(poLineItem.gross || 0).toFixed(4),
    discount: parseFloat(poLineItem.discount || 0).toFixed(4),
    discount_amount: parseFloat(poLineItem.discount_amount || 0).toFixed(4),
    tax_amount: parseFloat(poLineItem.tax_amount || 0).toFixed(4),
    po_amount: parseFloat(poLineItem.po_amount || 0).toFixed(4),
    min_price: parseFloat(poLineItem.min_price || 0).toFixed(4),
    max_price: parseFloat(poLineItem.max_price || 0).toFixed(4),
    received_qty: receivedQty,
    outstanding_quantity: (parseFloat(poLineItem.quantity || 0) - receivedQty).toFixed(3),
    supplier_id: entry.po_supplier_id || "",
    plant_id: entry.po_plant || "",
    payment_term_id: entry.po_payment_terms || "",
    shipping_preference_id: entry.po_shipping_preference || "",
    billing_state_id: entry.billing_address_state || "",
    billing_country_id: entry.billing_address_country || "",
    shipping_state_id: entry.shipping_address_state || "",
    shipping_country_id: entry.shipping_address_country || "",
    item_category_id: poLineItem.item_category_id || "",
    line_index: index + 1,
    organization_id: entry.organization_id,
    line_status: !poLineItem.line_status || poLineItem.line_status === '' || poLineItem.line_status === 'Draft' ? entry.po_status : poLineItem.line_status,
    po_created_by: {{global:nickname}}
  };

  updatedLineItem.push(formattedItem);
}

entry.partially_received = !entry.partially_received || entry.partially_received === '' ? `0 / ${updatedLineItem.length}` : entry.partially_received;
entry.fully_received = !entry.fully_received || entry.fully_received === '' ? `0 / ${updatedLineItem.length}` : entry.fully_received;
entry.po_total_gross = parseFloat(entry.po_total_gross || 0).toFixed(4);
entry.po_total_discount = parseFloat(entry.po_total_discount || 0).toFixed(4);
entry.po_total_tax = parseFloat(entry.po_total_tax || 0).toFixed(4);
entry.po_total = parseFloat(entry.po_total || 0).toFixed(4);
entry.myr_total_amount = parseFloat(entry.myr_total_amount || 0).toFixed(4);

entry.table_po = updatedLineItem;

return { entry };

const lineItem = {{node:code_fillback.data.entry.table_po}};

const uniqueItemIDs = [
  ...new Set(lineItem.filter((item) => item.item_id).map((item) => item.item_id))
];

return {
  itemIDs: uniqueItemIDs
}

const tablePO = {{node:get_po_full.data.data.table_po}} || [];

return {
  itemIDs: tablePO.map(item => item.item_id).filter(Boolean)
}

const latestLines = {{node:get_po_full.data.data.table_po}} || [];
const existing    = {{node:search_onorder.data.data}} || [];
const items       = {{node:search_items.data.data}} || [];
const poData      = {{node:code_get_latest.data.poData}};
const pageStatus  = poData.page_status;

const round3 = (n) => Math.round((parseFloat(n) || 0) * 1000) / 1000;

const baseQtyFor = (line) => {
  const itemData = items.find(d => String(d.id) === String(line.item_id));
  const altQty = parseFloat(line.quantity) || 0;
  let baseQty = altQty;
  if (itemData && Array.isArray(itemData.table_uom_conversion) && itemData.table_uom_conversion.length > 0) {
    const conv = itemData.table_uom_conversion.find(c => String(c.alt_uom_id) === String(line.quantity_uom));
    if (conv) baseQty = round3(altQty * parseFloat(conv.base_qty));
  }
  return baseQty;
};

const desired = [];
for (const [index, line] of latestLines.entries()) {
  const itemData = items.find(d => String(d.id) === String(line.item_id));
  if (!itemData) continue;
  desired.push({
    po_line_id: line.id,
    purchase_order_number: poData.purchase_order_no,
    material_id: line.item_id,
    purchase_order_line: index + 1,
    scheduled_qty: baseQtyFor(line),
    plant_id: poData.po_plant,
    organization_id: poData.organization_id,
    po_id: poData.id,
    parent_id: line.preq_id || null,
    parent_line_id: line.preq_line_id || null
  });
}

const toAdd = [], toUpdate = [], toDelete = [];
const usedExistingIds = new Set();

const findExisting = (d) => {
  let m = existing.find(e => e.po_line_id != null && String(e.po_line_id) === String(d.po_line_id) && !usedExistingIds.has(e.id));
  if (m) return m;
  return existing.find(e => !usedExistingIds.has(e.id) && String(e.material_id) === String(d.material_id) && Number(e.purchase_order_line) === Number(d.purchase_order_line));
};

const isNew = (pageStatus === 'Add' || pageStatus === 'Clone');

for (const d of desired) {
  const match = isNew ? null : findExisting(d);
  if (!match) {
    toAdd.push({
      purchase_order_number: d.purchase_order_number,
      material_id: d.material_id,
      purchase_order_line: d.purchase_order_line,
      scheduled_qty: d.scheduled_qty,
      open_qty: d.scheduled_qty,
      received_qty: 0,
      plant_id: d.plant_id,
      organization_id: d.organization_id,
      po_id: d.po_id,
      po_line_id: d.po_line_id,
      parent_id: d.parent_id,
      parent_line_id: d.parent_line_id
    });
  } else {
    usedExistingIds.add(match.id);
    const received = Math.max(0, round3(match.received_qty || 0));
    const newOpen = Math.max(0, round3(d.scheduled_qty - received));
    toUpdate.push({
      id: match.id,
      scheduled_qty: d.scheduled_qty,
      open_qty: newOpen,
      purchase_order_line: d.purchase_order_line,
      po_line_id: d.po_line_id
    });
  }
}

if (!isNew) {
  for (const e of existing) {
    if (!usedExistingIds.has(e.id)) toDelete.push({ id: e.id });
  }
}

return { toAdd, toUpdate, toDelete };

const poID = {{node:code_get_latest.data.poData.id}};
const poLineItem = {{node:get_po_full.data.data.table_po}} || [];
const preqData = {{node:search_preq.data.data}};
const onOrderData = {{node:search_onorder.data.data}} || [];
let latestPREQData = [];

if(preqData && preqData.length > 0) {
  for(const preq of preqData) {
    let processedItems = preq.table_pr.map(item => {
      const poItem = poLineItem.find(po => po.preq_line_id === item.id);
      const newItem = { ...item };
      let orderQty = 0;

      if(poItem) {
        const onOrderItem = onOrderData.length > 0 ? onOrderData.find(onOrder => onOrder.parent_line_id === item.id) : null;
        if(onOrderItem) {
          orderQty = parseFloat(item.order_qty || 0) - parseFloat(onOrderItem.scheduled_qty || 0) + parseFloat(poItem.quantity || 0);
        } else {
          orderQty = parseFloat(item.order_qty || 0) + parseFloat(poItem.quantity || 0);
        }
        newItem.order_qty = parseFloat(orderQty).toFixed(3);
        newItem.po_id = [...(item.po_id || []), poID];
        newItem.po_line_id = [...(item.po_line_id || []), poItem.id];
      }

      return newItem;
    });

    let preqStatus = preq.preq_status;
    if(preq.preq_type === 'Contract' && preq.preq_status !== 'Force Completed') {
      const isCompleted = processedItems.every(item =>
        parseFloat(item.pr_line_qty) === parseFloat(item.order_qty || 0)
      );
      preqStatus = isCompleted ? 'Completed' : 'Processing';
    } else if(preq.preq_status !== 'Force Completed') {
      preqStatus = 'Completed';
    }

    processedItems = processedItems.map((it) => {
      return { ...it, line_status: preqStatus };
    });

    latestPREQData.push({
      id: preq.id,
      preq_status: preqStatus,
      table_pr: processedItems,
    });
  }
}

return { latestPREQData };

const poData = {{node:code_get_latest.data.poData}};

return {
  data: {
    po_id: poData.id,
    po_no: poData.purchase_order_no
  }
}
